  {
    label: 'Default',
    meta: [
      { label: 'Value', value: '5' },
      { label: 'Range', value: '1 – 9' },
    ],
    config: {
      formValidationConfig: {
        formControlName: 'stateDefault',
        formControl: new FormControl(5),
