import { inject, Injectable, TemplateRef, Type } from '@angular/core';
import {
  EventBusService,
  GenerateIdPipe,
  IbeEventTypeEnum,
  ModalClosedEvent,
  ModalDialogActionType,
} from '@dcx/ui/libs';
import { NgbModal, NgbModalOptions, NgbModalRef } from '@ng-bootstrap/ng-bootstrap';
import { Observable, Subject } from 'rxjs';

import { ModalDialogComponent } from '../modal-dialog.component';
import { ModalDialogConfig } from '../models/modal-dialog.config';
import { ModalLayoutConfig } from '../models/modal-layout.config';

@Injectable({ providedIn: 'root' })
export class ModalDialogService {
  public readonly generateId = inject(GenerateIdPipe);
  private readonly modalSvc = inject(NgbModal);
  private readonly eventBusService = inject(EventBusService);
  private modalRef: NgbModalRef | null = null;

  /**
   * Subject for emitting actions from the modal if you are using the modal-dialog component, it
   * could be use to suscribe to cancel or confirm action.
   */
  private actionSubject!: Subject<ModalDialogActionType>;

  /**
   * Opens a modal dialog with the provided configuration and content.
   *
   * @param modalDialogConfig - Configuration options for the modal.
   * @param content - The content or component to display inside the modal.
   * @param componentInstanceConfig - Additional configuration for the component instance.
   * @param allowMultiple - Allows opening multiple modals when true.
   * @returns An Observable that emits modal actions.
   */
  /**
   * Opens a modal with strongly typed content targets. `content` mirrors the valid inputs for `NgbModal.open`
   * (Angular components, templates, or template ids) so callers get compile-time hints instead of `any`.
   * Optional `componentInstanceConfig` lets feature modules pass extra inputs to projected components.
   */
  public openModal(
    config: ModalDialogConfig,
    content: Type<unknown> | TemplateRef<unknown> | string = ModalDialogComponent,
    componentInstanceConfig?: Record<string, unknown>,
    allowMultiple: boolean = false
  ): Observable<ModalDialogActionType> {
    // Only prevents multiple modals if allowMultiple is false
    if (this.modalRef && !allowMultiple) {
      return this.actionSubject.asObservable();
    }

    const actionSubject = new Subject<ModalDialogActionType>();
    const options = this.buildModalOptions(config);
    const modalRef = this.modalSvc.open(content, options);

    if (!allowMultiple) {
      this.modalRef = modalRef;
      this.actionSubject = actionSubject;
    }

    if (modalRef.componentInstance) {
      modalRef.componentInstance.modalDialogConfig = { ...config };

      if (componentInstanceConfig) {
        modalRef.componentInstance.config = { ...componentInstanceConfig };
      }
    }

    modalRef.dismissed.subscribe(() => {
      actionSubject.next(ModalDialogActionType.BLUR);

      const event: ModalClosedEvent = {
        type: IbeEventTypeEnum.modalClosed,
        payload: {
          actionType: ModalDialogActionType.BLUR,
        },
      };
      this.eventBusService.notifyEvent(event);
    });

    if (modalRef.componentInstance?.closeModal) {
      modalRef.componentInstance.closeModal.subscribe(() => {
        if (allowMultiple) {
          modalRef.dismiss();
        } else {
          this.closeActiveModal();
        }
      });
    }

    if (modalRef.componentInstance?.actionEmitter) {
      modalRef.componentInstance.actionEmitter.subscribe((action: ModalDialogActionType) => {
        actionSubject.next(action);
      });
    }

    modalRef.result.finally(() => {
      if (!allowMultiple) {
        this.modalRef = null;
      }
      actionSubject.complete();
    });

    return actionSubject.asObservable();
  }

  public closeActiveModal(): void {
    this.modalRef?.dismiss();
  }

  public closeAllModals(): void {
    this.closeActiveModal();
    this.modalSvc.dismissAll();
  }

  /**
   * Updates the layout-related options (fullscreen, classes, size) of the currently active modal without
   * forcing a close/reopen cycle. Internally uses `NgbModalRef.update`, so it’s safe to call repeatedly
   * as breakpoints or themes change. No-ops if there’s no active modal or no layout config.
   */
  public updateActiveModalLayout(layoutConfig?: ModalLayoutConfig): void {
    if (!this.modalRef || !layoutConfig) {
      return;
    }

    this.modalRef.update({
      centered: layoutConfig.centered,
      size: layoutConfig.size,
      fullscreen: layoutConfig.fullscreen,
      modalDialogClass: layoutConfig.modalDialogClass,
      windowClass: layoutConfig.modalWrapperClass,
      backdropClass: layoutConfig.modalOverlayClass,
    });
  }

  private buildModalOptions(config: ModalDialogConfig): NgbModalOptions {
    const generatedId = this.generateId.transform('modalHeaderId_');

    config.ariaAttributes ??= {};
    config.ariaAttributes.ariaLabelledBy ??= generatedId;

    return {
      centered: config.layoutConfig?.centered ?? true,
      size: config.layoutConfig?.size,
      fullscreen: config.layoutConfig?.fullscreen,
      backdropClass: config.layoutConfig?.modalOverlayClass,
      windowClass: config.layoutConfig?.modalWrapperClass,
      modalDialogClass: config.layoutConfig?.modalDialogClass,
      ariaLabelledBy: config.ariaAttributes.ariaLabelledBy,
      ariaDescribedBy: config.ariaAttributes.ariaDescribedBy,
      backdrop: config.layoutConfig?.backdrop ?? true,
    };
  }
}

import { Injectable } from '@angular/core';
import { from, Observable, of } from 'rxjs';
import { catchError, map, switchMap } from 'rxjs/operators';

@Injectable({
  providedIn: 'root',
})
export class SlugCultureControlService {
  private readonly endpointGetTitleTab: string = '/configuration/api/v1/UI_PLUS/MultiTab/GetTabsTranslations';

  private isActiveTabParamPresent(searchParams: string): boolean {
    return searchParams.includes('activeTab');
  }

  public getFixedParameters(nextLang: string): Observable<string> {
    const searchParams: string = document.location.search;
    if (this.isActiveTabParamPresent(searchParams)) {
      return this.getActiveTabModification(nextLang, searchParams);
    } else {
      return of(searchParams);
    }
  }

  private getActiveTabModification(nextLang: string, searchParams: string): Observable<string> {
    const currentLang = this.getLangFromURL();
    const currentActiveTab = this.getActiveTabTextFromURL(searchParams) ?? '';
    const url =
      `${this.endpointGetTitleTab}` +
      `?nodeName=Members` +
      `&currentLang=${encodeURIComponent(currentLang)}` +
      `&nextLang=${encodeURIComponent(nextLang)}` +
      `&activeTab=${encodeURIComponent(currentActiveTab)}`;

    return from(fetch(url)).pipe(
      switchMap((res) => from(res.json() as Promise<{ translatedTabTitle?: string }>)),
      map((data) => {
        return data.translatedTabTitle
          ? this.getSearchWithActiveTab(data.translatedTabTitle, searchParams)
          : searchParams;
      }),
      catchError((error) => {
        console.error('Error fetching active tab translation:', error);
        return of(searchParams);
      })
    );
  }

  private getSearchWithActiveTab(newValue: string, searchParams: string): string {
    const params = new URLSearchParams(searchParams);
    if (params.has('activeTab')) {
      params.set('activeTab', newValue);
    }
    return `?${params.toString()}`;
  }

  private getActiveTabTextFromURL(searchParams: string): string | null {
    const urlParams = new URLSearchParams(searchParams);
    return urlParams.get('activeTab');
  }

  private getLangFromURL(): string {
    const url = globalThis.location.pathname;
    const segments = url.split('/').filter((segment) => segment.length > 0);
    if (segments.length === 0) {
      return 'en';
    }
    if (segments[0].length === 2) {
      return segments[0];
    }
    return segments[1] ?? 'en';
  }
}

import { Injectable, Signal, signal } from '@angular/core';
import { BehaviorSubject, Observable } from 'rxjs';

import { TabConfig } from '../models/tab.config';

/**
 * TabsService
 * Central service to publish tab selection events so that any component
 * (outside of the tab component tree) can react to tab changes.
 *
 * Features:
 * - Emits the currently selected TabConfig as an observable.
 * - Supports optional grouping (multiple independent tab contexts) via a group key.
 * - Exposes both RxJS (selectedTab$) and Angular Signals (selectedTabSignal) APIs.
 */
@Injectable({ providedIn: 'root' })
export class TabsService {
  private readonly groups = new Map<string, BehaviorSubject<TabConfig | null>>();
  private readonly groupSignals = new Map<string, Signal<TabConfig | null>>();

  /** Selects (publishes) a tab for the given group (default group if omitted). */
  public select(tab: TabConfig, group = 'default'): void {
    this.getSubject(group).next(tab);
    const sig = this.groupSignals.get(group) as any as { set?: (v: TabConfig | null) => void } | undefined;
    sig?.set?.(tab);
  }

  /** Observable stream for the selected tab in the specified group. */
  public selectedTab$(group = 'default'): Observable<TabConfig | null> {
    return this.getSubject(group).asObservable();
  }

  /** Signal accessor for template-friendly consumption. */
  public selectedTabSignal(group = 'default'): Signal<TabConfig | null> {
    if (!this.groupSignals.has(group)) {
      const subj = this.getSubject(group);
      const sig = signal<TabConfig | null>(subj.value);
      // Keep signal in sync when subject changes (lightweight manual subscription)
      subj.subscribe((v) => {
        const s = this.groupSignals.get(group) as any as { set?: (val: TabConfig | null) => void } | undefined;
        s?.set?.(v);
      });
      this.groupSignals.set(group, sig);
    }
    return this.groupSignals.get(group)!;
  }

  /** Synchronous getter for current selected tab in a group. */
  public getCurrent(group = 'default'): TabConfig | null {
    return this.getSubject(group).value;
  }

  private getSubject(group: string): BehaviorSubject<TabConfig | null> {
    if (!this.groups.has(group)) {
      this.groups.set(group, new BehaviorSubject<TabConfig | null>(null));
    }
    return this.groups.get(group)!;
  }
}

import { inject, Injectable } from '@angular/core';

import { Toast } from '../../toast/models/toast.model';

import { ToastStickyBehaviorService } from './toast-sticky-behavior.service';

@Injectable({ providedIn: 'root' })
export class ToastService {
  public toastCount: number = 0;
  public toastConfigs: Toast[] = [];
  private section: string = '';
  private readonly stickyCleanupFunctions = new Map<number, () => void>();

  private readonly stickyBehaviorService = inject(ToastStickyBehaviorService);

  public show(config: Toast, container: string): void {
    if (container) {
      this.toastCount++;
      this.toastConfigs.push(config);
      setTimeout(() => {
        const idToast = 'dynamicToast-' + (this.toastCount - 1);
        const dynamicToast = document.getElementById(idToast);
        const containerToast = document.getElementById(container);
        if (containerToast && dynamicToast) {
          containerToast.appendChild(dynamicToast);

          const cleanup = this.stickyBehaviorService.attachStickyBehavior(
            dynamicToast,
            containerToast,
            config.stickyViewportOffset
          );
          this.stickyCleanupFunctions.set(this.toastCount - 1, cleanup);
        }
      }, 10);
    }
  }

  public setSection(section: string): void {
    this.section = section;
  }

  public getSection(): string {
    return this.section;
  }

  public hidden(toastIndex: number): void {
    const toast = document.getElementById('dynamicToast-' + toastIndex);
    if (toast?.parentNode) {
      // Cleanup sticky behavior if exists
      const cleanup = this.stickyCleanupFunctions.get(toastIndex);
      if (cleanup) {
        cleanup();
        this.stickyCleanupFunctions.delete(toastIndex);
      }

      toast.remove();
    }
  }
}

import { DOCUMENT, isPlatformBrowser } from '@angular/common';
import { inject, Injectable, NgZone, PLATFORM_ID } from '@angular/core';

/**
 * Service to manage sticky behavior for toast components.
 * Handles scroll-based position changes from absolute to fixed.
 */
@Injectable({ providedIn: 'root' })
export class ToastStickyBehaviorService {
  private readonly STICKY_CLASS = 'toast--sticky-active';
  private readonly DEFAULT_VIEWPORT_OFFSET = 32;
  private readonly HEADER_HEIGHT_VAR = '--header-height';

  private readonly document = inject(DOCUMENT);
  private readonly ngZone = inject(NgZone);
  private readonly platformId = inject(PLATFORM_ID);

  private readonly stickyItems = new Map<HTMLElement, StickyToastItem>();

  private rafId: number | null = null;
  private listenersAttached = false;
  private readonly isBrowser = isPlatformBrowser(this.platformId);

  private headerHeightPx = 0;
  private headerHeightRaw = '';

  private readonly onScroll = (): void => {
    this.scheduleUpdate();
  };

  private readonly onResize = (): void => {
    this.refreshHeaderHeightIfChanged();
    this.recaptureOffsetsOnResize();
    this.scheduleUpdate();
  };

  /**
   * Attaches sticky scroll behavior to a toast element.
   * Expects the toast to be absolutely positioned relative to its container in normal mode.
   * @param toastElement The toast DOM element
   * @param containerElement The container element that holds the toast
   * @param viewportOffset Distance in pixels from header/viewport when sticky activates
   * @returns Cleanup function to disconnect observers/listeners for this toast
   */
  public attachStickyBehavior(
    toastElement: HTMLElement,
    containerElement: HTMLElement,
    viewportOffset: number = this.DEFAULT_VIEWPORT_OFFSET
  ): () => void {
    if (!this.isBrowser) {
      return () => undefined;
    }

    const originalInlineTop = toastElement.style.top;
    const originalInlineRight = toastElement.style.right;
    const originalInlineLeft = toastElement.style.left;

    const originalTopOffset = this.resolveOriginalTopOffset(toastElement, containerElement);
    const originalRightOffset = this.resolveOriginalRightOffset(toastElement, containerElement);

    this.stickyItems.set(toastElement, {
      toastElement,
      containerElement,
      originalInlineTop,
      originalInlineRight,
      originalInlineLeft,
      originalTopOffset,
      originalRightOffset,
      viewportOffset,
      hasBeenEvaluated: false,
      isSticky: false,
      appliedRightPx: null,
    });

    this.attachGlobalListeners();
    this.scheduleUpdate();

    const cleanup = (): void => {
      const item = this.stickyItems.get(toastElement);
      this.stickyItems.delete(toastElement);

      if (item) {
        this.deactivateStickyMode(
          toastElement,
          item.originalInlineTop,
          item.originalInlineRight,
          item.originalInlineLeft
        );
      } else {
        this.deactivateStickyMode(toastElement, originalInlineTop, originalInlineRight, originalInlineLeft);
      }

      this.detachGlobalListenersIfNeeded();
    };

    return cleanup;
  }

  /** Detaches sticky behavior and restores original styles for a toast. */
  public detach(toastElement: HTMLElement): void {
    const item = this.stickyItems.get(toastElement);
    if (item) {
      this.stickyItems.delete(toastElement);
      this.deactivateStickyMode(
        toastElement,
        item.originalInlineTop,
        item.originalInlineRight,
        item.originalInlineLeft
      );
    }
    this.detachGlobalListenersIfNeeded();
  }

  private calculateStickyThreshold(viewportOffset: number): number {
    return this.headerHeightPx + viewportOffset;
  }

  /** Reads `--header-height` from `:root` and caches the parsed pixel value. */
  private refreshHeaderHeightIfChanged(): boolean {
    if (!this.isBrowser) {
      return false;
    }

    const rootElement = this.document.documentElement;
    if (!rootElement) {
      return false;
    }

    const rawHeaderHeightValue = getComputedStyle(rootElement).getPropertyValue(this.HEADER_HEIGHT_VAR).trim();

    if (rawHeaderHeightValue === this.headerHeightRaw) {
      return false;
    }

    this.headerHeightRaw = rawHeaderHeightValue;

    if (!rawHeaderHeightValue) {
      this.headerHeightPx = 0;
      return true;
    }

    const parsed = Number.parseFloat(rawHeaderHeightValue);
    this.headerHeightPx = Number.isNaN(parsed) ? 0 : parsed;
    return true;
  }

  /** Returns toast top offset relative to its container via `getBoundingClientRect`. */
  private resolveOriginalTopOffset(toastElement: HTMLElement, containerElement: HTMLElement): number {
    const toastRect = toastElement.getBoundingClientRect();
    const containerRect = containerElement.getBoundingClientRect();
    return toastRect.top - containerRect.top;
  }

  /** Returns distance from toast right edge to container right edge via `getBoundingClientRect`. */
  private resolveOriginalRightOffset(toastElement: HTMLElement, containerElement: HTMLElement): number {
    const toastRect = toastElement.getBoundingClientRect();
    const containerRect = containerElement.getBoundingClientRect();
    return containerRect.right - toastRect.right;
  }

  /** Reverts sticky items to absolute, forces reflow, and re-captures offsets from fresh geometry. */
  private recaptureOffsetsOnResize(): void {
    this.stickyItems.forEach((item) => {
      if (item.isSticky) {
        this.deactivateStickyMode(
          item.toastElement,
          item.originalInlineTop,
          item.originalInlineRight,
          item.originalInlineLeft
        );
        item.isSticky = false;
        item.appliedRightPx = null;
      }
    });

    // getBoundingClientRect() forces synchronous reflow after the style changes above.
    this.stickyItems.forEach((item) => {
      if (!item.toastElement.isConnected || !item.containerElement.isConnected) {
        return;
      }

      item.originalTopOffset = this.resolveOriginalTopOffset(item.toastElement, item.containerElement);
      item.originalRightOffset = this.resolveOriginalRightOffset(item.toastElement, item.containerElement);
    });
  }

  private attachGlobalListeners(): void {
    if (this.listenersAttached || !this.isBrowser || !this.document.defaultView) {
      return;
    }

    const windowRef = this.document.defaultView;

    this.refreshHeaderHeightIfChanged();

    this.ngZone.runOutsideAngular(() => {
      windowRef.addEventListener('scroll', this.onScroll, { passive: true });
      windowRef.addEventListener('resize', this.onResize, { passive: true });
    });

    this.listenersAttached = true;
  }

  /** Removes global listeners when no sticky toasts remain. */
  private detachGlobalListenersIfNeeded(): void {
    if (this.stickyItems.size > 0 || !this.listenersAttached || !this.isBrowser || !this.document.defaultView) {
      return;
    }

    const windowRef = this.document.defaultView;

    windowRef.removeEventListener('scroll', this.onScroll);
    windowRef.removeEventListener('resize', this.onResize);

    this.listenersAttached = false;

    if (this.rafId !== null) {
      windowRef.cancelAnimationFrame(this.rafId);
      this.rafId = null;
    }
  }

  /** Batches updates via `requestAnimationFrame` to coalesce rapid scroll/resize events. */
  private scheduleUpdate(): void {
    if (this.rafId !== null || !this.isBrowser || !this.document.defaultView) {
      return;
    }

    const windowRef = this.document.defaultView;

    this.ngZone.runOutsideAngular(() => {
      this.rafId = windowRef.requestAnimationFrame(() => {
        this.rafId = null;
        this.updateStickyItems();
      });
    });
  }

  /** Viewport width excluding scrollbar — matches `position: fixed` coordinate system. */
  private getViewportWidth(): number {
    return this.document.documentElement?.clientWidth ?? this.document.defaultView?.innerWidth ?? 0;
  }

  private computeRightOffsetPx(containerRect: DOMRect, originalRightOffset: number): number | null {
    const viewportWidth = this.getViewportWidth();
    if (viewportWidth === 0) {
      return null;
    }

    const rightPx = viewportWidth - containerRect.right + originalRightOffset;

    if (!Number.isFinite(rightPx) || rightPx < 0 || rightPx > viewportWidth) {
      return null;
    }

    return Math.max(0, Math.round(rightPx));
  }

  private updateStickyItems(): void {
    if (this.stickyItems.size === 0) {
      return;
    }

    this.refreshHeaderHeightIfChanged();

    const windowRef = this.document.defaultView;
    const currentScrollY = windowRef ? windowRef.scrollY : 0;
    const toDetach: HTMLElement[] = [];

    this.stickyItems.forEach((item) => {
      if (!item.toastElement.isConnected || !item.containerElement.isConnected) {
        toDetach.push(item.toastElement);
        return;
      }

      // Skip sticky on initial load at scrollY === 0; allow activation if page restores with scroll.
      if (!item.hasBeenEvaluated && currentScrollY === 0) {
        item.hasBeenEvaluated = true;
        this.deactivateStickyMode(
          item.toastElement,
          item.originalInlineTop,
          item.originalInlineRight,
          item.originalInlineLeft
        );
        item.isSticky = false;
        item.appliedRightPx = null;
        return;
      }

      item.hasBeenEvaluated = true;

      const containerRect = item.containerElement.getBoundingClientRect();
      const stickyThreshold = this.calculateStickyThreshold(item.viewportOffset);

      const toastAbsoluteTop = containerRect.top + item.originalTopOffset;
      const shouldBeSticky = toastAbsoluteTop <= stickyThreshold;

      if (shouldBeSticky) {
        const computedRight = this.computeRightOffsetPx(containerRect, item.originalRightOffset);
        item.appliedRightPx = computedRight;

        this.activateStickyMode(item.toastElement, stickyThreshold, computedRight);
        item.isSticky = true;
        return;
      }

      if (item.isSticky) {
        this.deactivateStickyMode(
          item.toastElement,
          item.originalInlineTop,
          item.originalInlineRight,
          item.originalInlineLeft
        );
      }
      item.isSticky = false;
      item.appliedRightPx = null;
    });

    for (const toastElement of toDetach) {
      this.detach(toastElement);
    }
  }

  private activateStickyMode(toastElement: HTMLElement, stickyTop: number, rightPx: number | null): void {
    const stickyTopValue = `${stickyTop}px`;

    if (!toastElement.classList.contains(this.STICKY_CLASS)) {
      toastElement.classList.add(this.STICKY_CLASS);
    }

    if (toastElement.style.top !== stickyTopValue) {
      toastElement.style.top = stickyTopValue;
    }

    // `left` is controlled by CSS; only `right` is set inline.
    if (rightPx !== null) {
      const rightValue = `${rightPx}px`;
      if (toastElement.style.right !== rightValue) {
        toastElement.style.right = rightValue;
      }
    }
  }

  private deactivateStickyMode(
    toastElement: HTMLElement,
    originalInlineTop: string,
    originalInlineRight: string,
    originalInlineLeft: string
  ): void {
    if (toastElement.classList.contains(this.STICKY_CLASS)) {
      toastElement.classList.remove(this.STICKY_CLASS);
    }

    if (toastElement.style.top !== originalInlineTop) {
      toastElement.style.top = originalInlineTop;
    }

    if (toastElement.style.right !== originalInlineRight) {
      toastElement.style.right = originalInlineRight;
    }

    if (toastElement.style.left !== originalInlineLeft) {
      toastElement.style.left = originalInlineLeft;
    }
  }

  /** Restores all toasts to their original state and removes global listeners. */
  public cleanupAll(): void {
    for (const item of this.stickyItems.values()) {
      this.deactivateStickyMode(
        item.toastElement,
        item.originalInlineTop,
        item.originalInlineRight,
        item.originalInlineLeft
      );
    }

    this.stickyItems.clear();
    this.detachGlobalListenersIfNeeded();
  }
}

interface StickyToastItem {
  toastElement: HTMLElement;
  containerElement: HTMLElement;
  originalInlineTop: string;
  originalInlineRight: string;
  originalInlineLeft: string;
  originalTopOffset: number;
  originalRightOffset: number;
  viewportOffset: number;
  hasBeenEvaluated: boolean;
  isSticky: boolean;
  appliedRightPx: number | null;
}

