    gap: $description-list-layout-column-grid-gap;

    .#{$ds}description-list_item {
        display: flex;
        flex-direction: column;
        flex: 1 1 100%;
        gap: $description-list-layout-column-dd-list-item-grid-gap;
    }
}

// layout inline
.#{$ds}description-list--layout-inline {
    display: flex;
    flex-direction: var(--description-list-layout-inline-flex-direction, column);
    gap: var(--description-list-layout-inline-gap, calculateRem(8px) calculateRem(16px));

    .#{$ds}description-list_item {
        display: flex;
        align-items: flex-start;
        gap: var(--description-list-layout-inline-item-gap, $spacer-tiny);
    }
    .#{$ds}description-list_label_icon {
        .icon {
            line-height: var(--f-line-height);
        }
    }
}

// [Responsive]
@media #{$mobile} {
    // >=640px
    .#{$ds}description-list--layout-column {
        flex-wrap: nowrap;
    }
}

