        }
        &::-moz-range-track {
            @include slider-range-track;
        }

        // styles for IE
        &::-ms-thumb {
            width: $range-slider-thumb-size;
            height: $range-slider-thumb-size;
            border-radius: 50%;
            background-color: $range-slider-bar-background-color;
