        }
        &::-ms-track {
            width: 100%;
            color: transparent;
            border-color: transparent;
            height: $range-slider-bar-height;
            background: $range-slider-selected-range-background-color;
            border-radius: $range-slider-bar-border-radius;
            cursor: pointer;
        }
        &::-ms-fill-lower,
        &::-ms-fill-upper {
            border-radius: $range-slider-bar-border-radius;
            background: $range-slider-bar-background-color;
        }
        &::-ms-tooltip {
            display: none;
        }

        // !Deprecation note: this styles must be removed when current IBE remove input[type=range]:focus outline:0 fropm its reset.scss file
        &:focus-visible {
            @include accessibility-outline;
