{
  name: 'Positions',
  render: () => ({
    template: `
      <div style="display:flex; gap:16px; flex-wrap:wrap;">
        <mock-storybook-offcanvas [offCanvasConfig]="positionConfigs[0]" [buttonLabel]="positionLabels[0]"></mock-storybook-offcanvas>
        <mock-storybook-offcanvas [offCanvasConfig]="positionConfigs[1]" [buttonLabel]="positionLabels[1]"></mock-storybook-offcanvas>
        <mock-storybook-offcanvas [offCanvasConfig]="positionConfigs[2]" [buttonLabel]="positionLabels[2]"></mock-storybook-offcanvas>
        <mock-storybook-offcanvas [offCanvasConfig]="positionConfigs[3]" [buttonLabel]="positionLabels[3]"></mock-storybook-offcanvas>
      </div>
    `,
    props: {
      positionConfigs: POSITION_VARIANTS,
      positionLabels: POSITION_LABELS,
    },
  }),
  play: async ({ canvasElement }) => {
    const CANVAS = within(canvasElement);
    const BUTTONS = await CANVAS.findAllByRole('button', { name: 'Open Offcanvas' });
    await expect(BUTTONS).toHaveLength(4);

    const USER = userEvent.setup();
    await USER.click(BUTTONS[0]);
    await expect(document.body.querySelector('.offcanvas-bottom')).toBeTruthy();
    await USER.click(document.body.querySelector('button.btn-close') as HTMLButtonElement);
  },
}

{
  name: 'Selected Page Position',
  render: () => ({
    props: {
      variants: POSITION_VARIANTS,
    },
    template: `
      <div style="${VARIANT_GRID_STYLES}">
        <div *ngFor="let variant of variants" style="${VARIANT_CARD_STYLES}">
          <h4 style="${VARIANT_TITLE_STYLES}">{{ variant.label }}</h4>
          <p style="${VARIANT_DESCRIPTION_STYLES}">{{ variant.description }}</p>
          <ds-paginator [config]="variant.config"></ds-paginator>
        </div>
      </div>
    `,
  }),
  play: async ({ canvasElement }) => {
    const canvas = within(canvasElement);

    // Wait for translations to load and paginators to render
    let navs: HTMLElement[] = [];
    await waitFor(() => {
      navs = canvas.getAllByRole('navigation');
      expect(navs).toHaveLength(POSITION_VARIANTS.length);
    });
    const disabledButtons = canvasElement.querySelectorAll('button:disabled');
    expect(disabledButtons.length).toBeGreaterThan(0);
    const activePages = canvasElement.querySelectorAll('[aria-current="page"]');
    expect(activePages.length).toBe(POSITION_VARIANTS.length);
  },
}

