  name: 'Interactive Menu Example',
  render: () => ({
    template: `
      <div style="position: relative; display: inline-block;">
        <icon-button
          [config]="menuButtonConfig"
          (clickEvent)="toggleMenu()">
        </icon-button>

        @if (isMenuOpen) {
          <div
            id="dropdown-menu"
            role="menu"
            style="
              position: absolute;
              top: 100%;
              left: 0;
              margin-top: 8px;
              background: white;
              border: 1px solid #ccc;
              border-radius: 4px;
              box-shadow: 0 2px 8px rgba(0,0,0,0.15);
              min-width: 200px;
              z-index: 1000;
            ">
            <button
              role="menuitem"
              (click)="selectOption('Profile')"
              style="
                display: block;
                width: 100%;
                padding: 12px 16px;
                border: none;
                background: none;
                text-align: left;
                cursor: pointer;
              ">
              Profile
            </button>
            <button
              role="menuitem"
              (click)="selectOption('Settings')"
              style="
                display: block;
                width: 100%;
                padding: 12px 16px;
                border: none;
                background: none;
                text-align: left;
                cursor: pointer;
              ">
              Settings
            </button>
            <button
              role="menuitem"
              (click)="selectOption('Logout')"
              style="
                display: block;
                width: 100%;
                padding: 12px 16px;
                border: none;
                background: none;
                text-align: left;
                cursor: pointer;
              ">
              Logout
            </button>
          </div>
        }
      </div>
    `,
    props: {
      isMenuOpen: false,
      menuButtonConfig: {
        icon: {
          name: 'menu-justify',
        },
        ariaAttributes: {
          ariaLabel: 'Open menu',
          ariaHaspopup: 'menu',
          ariaExpanded: false,
          ariaControls: 'dropdown-menu',
        },
      },
      toggleMenu(): void {
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const SELF = this as any;
        SELF.isMenuOpen = !SELF.isMenuOpen;
        SELF.menuButtonConfig.ariaAttributes.ariaExpanded = SELF.isMenuOpen;
      },
      selectOption(option: string): void {
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const SELF = this as any;
        console.log('Selected:', option);
        SELF.isMenuOpen = false;
        SELF.menuButtonConfig.ariaAttributes.ariaExpanded = false;
      },
    },
  }),
  play: async ({ canvasElement }) => {
    const CANVAS = within(canvasElement);
    const USER = userEvent.setup();
    const MENU_BUTTON = await CANVAS.findByRole('button', { name: 'Open menu' });

    await expect(CANVAS.queryByRole('menu')).not.toBeInTheDocument();

    await USER.click(MENU_BUTTON);
    const MENU = await CANVAS.findByRole('menu');
    await expect(MENU_BUTTON).toHaveAttribute('aria-expanded', 'true');
    await expect(MENU).toBeInTheDocument();

    const PROFILE_OPTION = await CANVAS.findByRole('menuitem', { name: 'Profile' });
    await USER.click(PROFILE_OPTION);

    await expect(CANVAS.queryByRole('menu')).not.toBeInTheDocument();
    await expect(MENU_BUTTON).toHaveAttribute('aria-expanded', 'false');
  },
}

